#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *h = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld", &h[i]);
        long long *left = (long long*)malloc(N*sizeof(long long));
        long long *right = (long long*)malloc(N*sizeof(long long));
        long long cur=0;
        for(int i=0;i<N;i++){
            if(i==0) left[i]=h[i];
            else left[i]= (h[i]>left[i-1])?h[i]:left[i-1];
        }
        for(int i=N-1;i>=0;i--){
            if(i==N-1) right[i]=h[i];
            else right[i]= (h[i]>right[i+1])?h[i]:right[i+1];
        }
        long long maxSection=0, sum=0;
        for(int i=0;i<N;i++){
            long long water = left[i] < right[i] ? left[i] - h[i] : right[i] - h[i];
            if(water<0) water=0;
            if(water>0){
                sum += water;
                if(sum>maxSection) maxSection=sum;
            }else{
                sum=0;
            }
        }
        printf("%lld\n", maxSection);
        free(h); free(left); free(right);
    }
    return 0;
}

