import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        h = [int(next(it)) for _ in range(N)]
        left = [0]*N
        right = [0]*N
        for i in range(N):
            left[i] = h[i] if i==0 else max(left[i-1], h[i])
        for i in range(N-1, -1, -1):
            right[i] = h[i] if i==N-1 else max(right[i+1], h[i])
        max_section = cur = 0
        for i in range(N):
            water = min(left[i], right[i]) - h[i]
            if water > 0:
                cur += water
                if cur > max_section:
                    max_section = cur
            else:
                cur = 0
        out_lines.append(str(max_section))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

